t.script:
                //
(function () {
    'use strict';
    var INTERVAL = 15000;
    var A = [
        { key: 'open_tickets',     sel: '[data-key="open_tickets"] .stat-value' },
        { key: 'total_tickets',    sel: '[data-key="total_tickets"] .stat-value' },
        { key: 'high_priority',    sel: '[data-key="high_priority"] .stat-value' },
        { key: 'urgent',           sel: '[data-key="urgent"] .stat-value' },
        { key: 'avg_open_hours',   sel: '[data-key="avg_open_hours"] .stat-value' },
        { key: 'total_hours',      sel: '[data-key="total_hours"] .stat-value' },
        { key: 'avg_high_hours',   sel: '[data-key="avg_high_hours"] .stat-value' },
        { key: 'avg_urgent_hours', sel: '[data-key="avg_urgent_hours"] .stat-value' },
        { key: 'resolved_tickets', sel: '[data-key="resolved_tickets"] .stat-value' },
        { key: 'solve_rate',       sel: '[data-key="solve_rate"] .stat-value', sfx: '%' },
        { key: 'high_resolved',    sel: '[data-key="high_resolved"] .stat-value' },
        { key: 'urgent_resolved',  sel: '[data-key="urgent_resolved"] .stat-value' }
    ];
    var P = [
        { key: 'today_closed',       sel: '[data-key="today_closed"] .performance-value' },
        { key: 'avg_resolve_rate',   sel: '[data-key="avg_resolve_rate"] .performance-value', sfx: '%' },
        { key: 'daily_target',       sel: '[data-key="daily_target"] .performance-value', sfx: '%' },
        { key: 'achievement',        sel: '[data-key="achievement"] .performance-value', sfx: '%' },
        { key: 'sample_performance', sel: '[data-key="sample_performance"] .score-badge', sfx: '%' }
    ];
    function upd(sel, val, sfx) { var el = document.querySelector(sel); if (el) el.textContent = val + (sfx || ''); }
    function flash(sel) {
        var el = document.querySelector(sel);
        if (el) { el.style.transition = 'color 0.3s'; el.style.color = '#0284c7'; setTimeout(function () { el.style.color = ''; }, 600); }
    }
    function updBar(v) {
        var b = document.querySelector('.progress-bar');
        if (b) { b.style.width = v + '%'; b.className = 'progress-bar ' + (v >= 80 ? 'bg-success' : 'bg-warning'); }
    }
    function updBarLabel(v) {
        var ls = document.querySelectorAll('.progress-label span');
        if (ls.length >= 2) ls[1].textContent = v + '%';
    }
    function updTime() {
        var t = new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
        document.querySelectorAll('.last-updated').forEach(function (el) { el.innerHTML = '<i class="bi bi-clock me-1"></i>Updated at ' + t; });
    }
    function run() {
        fetch('/customer_support/dashboard/analytics', { method: 'GET', credentials: 'same-origin', headers: { 'Accept': 'application/json' } })
        .then(function (r) { if (!r.ok) throw new Error(r.status); return r.json(); })
        .then(function (d) {
            var a = d.analytics || {}, p = d.performance || {};
            A.forEach(function (i) { var v = a[i.key]; if (v !== undefined) { upd(i.sel, v, i.sfx || ''); flash(i.sel); } });
            P.forEach(function (i) { var v = p[i.key]; if (v !== undefined) upd(i.sel, v, i.sfx || ''); });
            if (p.achievement !== undefined) { updBar(p.achievement); updBarLabel(p.achievement); }
            updTime();
        })
        .catch(function (e) { console.warn('Analytics refresh failed:', e); });
    }
    document.addEventListener('DOMContentLoaded', function () { run(); setInterval(run, INTERVAL); });
})();
                //

                //
document.addEventListener('DOMContentLoaded', function () {

    // ── AUTO-DISMISS ALERTS ───────────────────────────────────────────────
    setTimeout(function () {
        document.querySelectorAll('.alert').forEach(function (a) {
            try { new bootstrap.Alert(a).close(); } catch (e) { a.style.display = 'none'; }
        });
    }, 5000);

    // ── KANBAN COUNTS ─────────────────────────────────────────────────────
    function updatePortalCounts() {
        ['new', 'in_progress', 'resolved', 'closed'].forEach(function (state) {
            var col = document.getElementById('portal-col-' + state);
            var countEl = document.getElementById('portal-count-' + state);
            if (col && countEl) countEl.textContent = col.querySelectorAll('.kanban-card').length;
        });
    }
    updatePortalCounts();

    // ── PAGE SWITCHING ────────────────────────────────────────────────────
    var pages = {
        overview:  document.getElementById('portal-overview-page'),
        kanban:    document.getElementById('portal-kanban-page'),
        reporting: document.getElementById('portal-reporting-page')
    };
    var kanbanBtn = document.getElementById('portalKanbanBtn');

    function hideAllPages() {
        Object.keys(pages).forEach(function (k) { if (pages[k]) pages[k].style.display = 'none'; });
    }
    function setActiveNav(navId, isKanban) {
        document.querySelectorAll('.header-nav .nav-link').forEach(function (l) { l.classList.remove('active'); });
        var el = document.getElementById(navId);
        if (el) el.classList.add('active');
        if (kanbanBtn) kanbanBtn.classList.toggle('active', !!isKanban);
    }
    function showOverview()  { hideAllPages(); pages.overview.style.display = 'block';   setActiveNav('portalOverviewNav', false); }
    function showKanban()    { hideAllPages(); pages.kanban.style.display = 'block';     setActiveNav('portalTicketsNav', true);  updatePortalCounts(); }
    function showReporting() {
        hideAllPages(); pages.reporting.style.display = 'block';
        setActiveNav('portalReportingNav', false);
        loadPortalReports();
    }

    var overviewNav = document.getElementById('portalOverviewNav');
    if (overviewNav) overviewNav.addEventListener('click', function (e) { e.preventDefault(); showOverview(); });
    var ticketsNav = document.getElementById('portalTicketsNav');
    if (ticketsNav) ticketsNav.addEventListener('click', function (e) {
        e.preventDefault();
        window.location.href = '/customer_support/tickets/list';
    });
    var reportingNav = document.getElementById('portalReportingNav');
    if (reportingNav) reportingNav.addEventListener('click', function (e) { e.preventDefault(); showReporting(); });
    var reportActionCard = document.getElementById('portalReportActionCard');
    if (reportActionCard) reportActionCard.addEventListener('click', function (e) { e.preventDefault(); showReporting(); });
    var listBtn = document.getElementById('portalListBtn');
    if (listBtn) listBtn.addEventListener('click', function () { window.location.href = '/customer_support/tickets/kanban'; });
    var kanbanActiveBtn = document.getElementById('portalKanbanActiveBtn');
    if (kanbanActiveBtn) kanbanActiveBtn.addEventListener('click', function () { showKanban(); });

    document.querySelectorAll('#portal-kanban-page .kanban-card').forEach(function (card) {
        card.addEventListener('click', function () {
            var id = this.getAttribute('data-ticket-id');
            if (id) window.location.href = '/customer_support/customer/ticket/' + id;
        });
    });
    document.querySelectorAll('.action-card').forEach(function (card) {
        card.addEventListener('click', function (e) {
            var href = this.getAttribute('href');
            if (!href || href === '#' || href.endsWith('#')) {
                e.preventDefault();
                var self = this;
                self.style.transform = 'scale(0.95)';
                setTimeout(function () { self.style.transform = ''; }, 150);
            }
        });
    });

    // ── NOTIFICATION BELL ─────────────────────────────────────────────────
    var bell      = document.getElementById('portalNotifBell');
    var dropdown  = document.getElementById('portalNotifDropdown');
    var badge     = document.getElementById('portalNotifBadge');
    var notifList = document.getElementById('portalNotifList');

    if (bell && dropdown) {
        bell.addEventListener('click', function (e) { e.stopPropagation(); dropdown.classList.toggle('open'); });
        document.addEventListener('click', function () { dropdown.classList.remove('open'); });
        dropdown.addEventListener('click', function (e) { e.stopPropagation(); });
    }
    var markReadBtn = document.getElementById('portalMarkRead');
    if (markReadBtn) {
        markReadBtn.addEventListener('click', function () {
            fetch('/customer_support/customer/notifications/mark_read', { method: 'POST', credentials: 'same-origin', headers: { 'Accept': 'application/json' } })
            .then(function () {
                if (badge) { badge.classList.add('d-none'); badge.textContent = '0'; }
                if (notifList) { notifList.innerHTML = '<div class="notif-empty"><i class="bi bi-check-circle-fill" style="font-size:2rem;color:#22c55e;display:block;margin-bottom:.5rem;"></i>All caught up!</div>'; }
            })
            .catch(function (e) { console.warn('Mark read failed:', e); });
        });
    }
    var viewTicketsLink = document.getElementById('portalNotifViewTickets');
    if (viewTicketsLink) {
        viewTicketsLink.addEventListener('click', function (e) {
            e.preventDefault();
            if (dropdown) dropdown.classList.remove('open');
            showKanban();
        });
    }
    function sanitise(str) { var d = document.createElement('div'); d.textContent = String(str || ''); return d.innerHTML; }
    function renderNotifications(items) {
        if (!notifList) return;
        if (!items || !items.length) {
            notifList.innerHTML = '<div class="notif-empty"><i class="bi bi-check-circle-fill" style="font-size:2rem;color:#22c55e;display:block;margin-bottom:.5rem;"></i>No new notifications</div>';
            if (badge) badge.classList.add('d-none');
            return;
        }
        if (badge) { badge.textContent = items.length; badge.classList.remove('d-none'); }
        var typeLabels = { status_change: 'Status Update', assigned: 'Assigned', sla_breach: 'SLA Breach' };
        notifList.innerHTML = items.map(function (n) {
            var cls       = sanitise(n.cls   || 'status');
            var icon      = sanitise(n.icon  || 'bi-bell-fill');
            var ticketName = sanitise(n.ticket_name || n.ticket_id || '');
            var typeLabel  = sanitise(typeLabels[n.type] || 'Notification');
            var msg       = sanitise(n.message || '');
            var time      = sanitise(n.time   || '');
            var title     = ticketName ? ticketName + ' &middot; ' + typeLabel : typeLabel;
            return '<div class="notif-item">'
                + '<div class="notif-icon-wrap ' + cls + '"><i class="bi ' + icon + '"></i></div>'
                + '<div class="notif-body">'
                +   '<div class="notif-title">' + title + '</div>'
                +   '<div class="notif-sub">' + msg + '</div>'
                +   '<div class="notif-time-text">' + time + '</div>'
                + '</div>'
                + '<div class="notif-dot ' + cls + '"></div>'
                + '</div>';
        }).join('');
    }
    function loadNotifications() {
        fetch('/customer_support/customer/notifications', { method: 'GET', credentials: 'same-origin', headers: { 'Accept': 'application/json' } })
        .then(function (r) { return r.json(); })
        .then(function (data) { renderNotifications(data.notifications || []); })
        .catch(function () { renderNotifications([]); });
    }
    loadNotifications();
    setInterval(loadNotifications, 30000);

    // ── PORTAL REPORTS ────────────────────────────────────────────────────
    var _portalRptLoaded = false;

    function prJsonCall(url, params) {
        return fetch(url, {
            method: 'POST',
            credentials: 'same-origin',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ jsonrpc: '2.0', method: 'call', params: params || {} })
        }).then(function (r) { return r.json(); }).then(function (d) { return d.result || d; });
    }

    function loadPortalReports() {
        if (_portalRptLoaded) return;
        var loading = document.getElementById('portalRptLoading');
        var empty   = document.getElementById('portalRptEmpty');
        var list    = document.getElementById('portalRptList');
        if (loading) loading.style.display = 'flex';
        if (empty)   empty.style.display   = 'none';
        if (list)    list.style.display    = 'none';

        prJsonCall('/customer_support/customer/reports/list', {})
        .then(function (res) {
            if (loading) loading.style.display = 'none';
            var reports = (res.reports || []);
            if (!reports.length) {
                if (empty) empty.style.display = 'block';
                return;
            }
            var tbody = document.getElementById('portalRptBody');
            if (tbody) {
                tbody.innerHTML = reports.map(function (r) {
                    var typeTag = r.project_type
                        ? '<span style="flex-shrink:0;font-size:.7rem;font-weight:600;letter-spacing:.04em;background:#e0f2fe;color:#059669;border:1px solid rgba(2,132,199,0.2);border-radius:20px;padding:.2rem .65rem;">' + escH(r.project_type) + '</span>'
                        : '';
                    var keyTag = r.project_key
                        ? '<span style="display:inline-block;margin-top:.35rem;font-size:.68rem;font-weight:600;letter-spacing:.05em;background:#f0f9ff;color:#5b7fa6;border-radius:5px;padding:.1rem .45rem;">' + escH(r.project_key) + '</span>'
                        : '';
                    return '<div style="background:#fff;border:1px solid rgba(12,74,110,0.1);border-radius:14px;box-shadow:0 2px 10px rgba(12,74,110,0.07);padding:1.3rem 1.4rem;display:flex;flex-direction:column;gap:.9rem;">'
                        + '  <div style="display:flex;align-items:flex-start;justify-content:space-between;gap:.75rem;">'
                        + '    <div>'
                        + '      <div style="font-weight:700;font-size:.97rem;color:#065f46;line-height:1.3;">' + escH(r.project_name) + '</div>'
                        + keyTag
                        + '    </div>'
                        + typeTag
                        + '  </div>'
                        + '  <div style="display:flex;flex-direction:column;gap:.4rem;padding:.75rem;background:#f0f9ff;border-radius:9px;">'
                        + '    <div style="display:flex;align-items:center;gap:.55rem;font-size:.81rem;color:#5b7fa6;">'
                        + '      <i class="bi bi-calendar3" style="color:#059669;font-size:.85rem;"></i>'
                        + '      <span>Generated: <strong style="color:#065f46;">' + escH(r.generated_on || '—') + '</strong></span>'
                        + '    </div>'
                        + '    <div style="display:flex;align-items:center;gap:.55rem;font-size:.81rem;color:#5b7fa6;">'
                        + '      <i class="bi bi-send-check" style="color:#059669;font-size:.85rem;"></i>'
                        + '      <span>Received: <strong style="color:#065f46;">' + escH(r.forwarded_on || '—') + '</strong></span>'
                        + '    </div>'
                        + '  </div>'
                        + '  <button style="width:100%;background:#059669;color:#fff;border:none;border-radius:9px;padding:.55rem 1rem;font-size:.85rem;font-weight:600;cursor:pointer;display:flex;align-items:center;justify-content:center;gap:.45rem;transition:background .18s;" onmouseover="this.style.background=\'#0284c7\'" onmouseout="this.style.background=\'#0c4a6e\'" onclick="portalOpenReport(' + r.id + ')">'
                        + '    <i class="bi bi-eye"></i> Preview &amp; Download'
                        + '  </button>'
                        + '</div>';
                }).join('');
            }
            if (list) list.style.display = 'block';
            _portalRptLoaded = true;
        })
        .catch(function (e) {
            console.error('loadPortalReports error:', e);
            if (loading) loading.innerHTML = '<div style="display:flex;flex-direction:column;align-items:center;gap:.75rem;padding:3rem 0;"><div style="width:56px;height:56px;background:#fff1f0;border-radius:50%;display:flex;align-items:center;justify-content:center;"><i class="bi bi-exclamation-triangle" style="font-size:1.5rem;color:#dc2626;"></i></div><span style="color:#dc2626;font-weight:600;font-size:.92rem;">Could not load reports</span><span style="color:#5b7fa6;font-size:.83rem;">Please refresh the page to try again.</span></div>';
        });
    }

    function escH(s) {
        return String(s || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
    }

    window.portalOpenReport = function (fwdId) {
        var body  = document.getElementById('portalRptModalBody');
        var title = document.getElementById('portalRptModalTitle');
        var sub   = document.getElementById('portalRptModalSub');
        var dlBtn = document.getElementById('portalRptDownloadBtn');
        if (body) body.innerHTML = '<div style="padding:2rem;text-align:center;color:#6c757d;">'
            + '<div class="spinner-border text-primary" role="status"></div>'
            + '<div style="margin-top:.75rem;">Loading report…</div></div>';
        if (dlBtn) { dlBtn.disabled = true; dlBtn.innerHTML = '<i class="bi bi-download me-1"></i>Download PDF'; }
        new bootstrap.Modal(document.getElementById('portalRptModal')).show();

        prJsonCall('/customer_support/customer/report/detail', { report_id: fwdId })
        .then(function (res) {
            if (res.error || !res.report) {
                if (body) body.innerHTML = '<div style="padding:2rem;color:#dc2626;">' + escH(res.error || 'Failed to load report.') + '</div>';
                return;
            }
            var r = res.report;
            if (title) title.textContent = r.project_name + ' — Project Closure Report';
            if (sub)   sub.textContent   = 'Ref: ' + (r.project_key || '-') + '  ·  Generated ' + r.generated_on;
            var html = buildClosureReportHtml(r);
            if (body) body.innerHTML = html;
            if (dlBtn) {
                dlBtn.disabled = false;
                dlBtn.onclick = function () { portalDownloadPdf(r.project_name, dlBtn); };
            }
        })
        .catch(function (e) {
            console.error('portalOpenReport error:', e);
            if (body) body.innerHTML = '<div style="padding:2rem;color:#dc2626;">Network error. Please try again.</div>';
        });
    };

    function portalDownloadPdf(projectName, btn) {
        var el  = document.getElementById('portalRptModalBody');
        var filename = ((projectName || 'closure_report') + '_closure_report').replace(/\s+/g, '_').toLowerCase() + '.pdf';
        if (btn) { btn.disabled = true; btn.textContent = 'Generating…'; }
        html2pdf().set({
            margin:      [10, 10, 10, 10],
            filename:    filename,
            image:       { type: 'jpeg', quality: 0.97 },
            html2canvas: { scale: 2, useCORS: true, logging: false },
            jsPDF:       { unit: 'mm', format: 'a4', orientation: 'portrait' },
            pagebreak:   { mode: ['css', 'legacy'] }
        }).from(el).save().then(function () {
            if (btn) { btn.disabled = false; btn.innerHTML = '<i class="bi bi-download me-1"></i>Download PDF'; }
        });
    }

    function buildClosureReportHtml(r) {
        var team      = Array.isArray(r.team) ? r.team : [];
        var customers = Array.isArray(r.customers) ? r.customers : [];
        var allTkts   = Array.isArray(r.all_ticket_details) ? r.all_ticket_details : [];
        var slaRate   = r.sla_rate || 0;
        var resolveRate = r.resolve_rate || 0;

        function e(s) { return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
        var S = {
            wrap:    'font-family:"Segoe UI",Arial,sans-serif;color:#1a1a2e;background:#fff;padding:2rem 2.2rem;',
            secHead: 'font-size:.7rem;font-weight:700;text-transform:uppercase;letter-spacing:.1em;color:#1a3a5c;border-bottom:2px solid #1a3a5c;padding-bottom:.35rem;margin:1.4rem 0 .75rem;',
            th:      'padding:.55rem .7rem;text-align:left;font-size:.72rem;font-weight:700;text-transform:uppercase;letter-spacing:.06em;background:#1a3a5c;color:#fff;white-space:nowrap;',
            td:      'padding:.5rem .7rem;font-size:.8rem;border-bottom:1px solid #e9ecef;vertical-align:top;',
            tdBold:  'padding:.5rem .7rem;font-size:.8rem;border-bottom:1px solid #e9ecef;font-weight:700;',
            label:   'font-size:.72rem;color:#6c757d;text-transform:uppercase;letter-spacing:.05em;',
            val:     'font-size:.9rem;font-weight:600;color:#1a1a2e;margin-top:.1rem;',
        };
        function sec(txt, newPage) {
            var pb = newPage ? 'page-break-before:always;break-before:page;' : '';
            return '<div style="' + S.secHead + pb + '">' + txt + '</div>';
        }
        function kv(lbl, val) {
            return '<div style="margin-bottom:.55rem;"><div style="' + S.label + '">' + lbl + '</div><div style="' + S.val + '">' + val + '</div></div>';
        }
        function slaCell(st) {
            var b = (st||'').toLowerCase()==='breached';
            return '<span style="display:inline-block;padding:.15rem .5rem;border-radius:3px;font-size:.7rem;font-weight:700;' + (b?'background:#fde8e6;color:#922b21;':'background:#d5f5e3;color:#1e8449;') + '">' + (b?'BREACHED':'MET') + '</span>';
        }
        function stateCell(st) {
            var s=(st||'').toLowerCase();
            var bg=s.includes('resolv')||s.includes('clos')?'#d5f5e3':s.includes('progress')?'#fef9e7':'#f2f3f4';
            var cl=s.includes('resolv')||s.includes('clos')?'#1e8449':s.includes('progress')?'#9a7d0a':'#555';
            return '<span style="display:inline-block;padding:.15rem .45rem;border-radius:3px;font-size:.7rem;font-weight:600;background:'+bg+';color:'+cl+';">'+e(st)+'</span>';
        }
        function priCell(p) {
            var s=(p||'').toLowerCase();
            var bg=s==='urgent'?'#fde8e6':s==='high'?'#fef3cd':s==='low'?'#f2f3f4':'#e8f4fd';
            var cl=s==='urgent'?'#922b21':s==='high'?'#9a7d0a':s==='low'?'#555':'#1a6a9a';
            return '<span style="display:inline-block;padding:.15rem .45rem;border-radius:3px;font-size:.7rem;font-weight:600;background:'+bg+';color:'+cl+';">'+e(p)+'</span>';
        }
        function statBox(val, lbl, color) {
            return '<div style="flex:1;text-align:center;padding:.75rem .5rem;border:1px solid #e9ecef;border-radius:6px;border-top:3px solid '+(color||'#1a3a5c')+';page-break-inside:avoid;break-inside:avoid;">'
                + '<div style="font-size:1.5rem;font-weight:700;color:'+(color||'#1a1a2e')+';">'+val+'</div>'
                + '<div style="font-size:.68rem;color:#6c757d;text-transform:uppercase;letter-spacing:.05em;margin-top:.2rem;">'+lbl+'</div></div>';
        }

        var headerHtml = '<div style="display:flex;justify-content:space-between;align-items:flex-start;padding-bottom:1.2rem;border-bottom:3px solid #1a3a5c;margin-bottom:1.2rem;page-break-inside:avoid;break-inside:avoid;">'
            + '<div>'
            + '<div style="font-size:.68rem;font-weight:700;text-transform:uppercase;letter-spacing:.15em;color:#6c757d;margin-bottom:.35rem;">Official Project Closure Report</div>'
            + '<div style="margin:0;font-size:1.45rem;font-weight:700;letter-spacing:.5px;color:#1a3a5c;">'+e(r.project_name)+'</div>'
            + '<div style="font-size:.82rem;color:#6c757d;margin-top:.25rem;">'+e(r.project_type||'')+(r.project_key?'&nbsp;&nbsp;|&nbsp;&nbsp;Ref: <strong>'+e(r.project_key)+'</strong>':'')+'</div>'
            + (r.customer_name ? '<div style="font-size:.82rem;font-weight:600;color:#1a3a5c;margin-top:.3rem;">Prepared for: '+e(r.customer_name)+'</div>' : '')
            + '</div>'
            + '<div style="text-align:right;">'
            + '<div style="font-size:.72rem;color:#6c757d;">Dragon Coders</div>'
            + '<div style="font-size:.68rem;color:#9ca3af;margin-top:.15rem;">Generated: '+e(r.generated_on)+'</div>'
            + '</div></div>';

        var overviewHtml = sec('Project Overview')
            + '<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:.5rem 1.5rem;page-break-inside:avoid;break-inside:avoid;">'
            + kv('Project Reference', e(r.project_key||'-')) + kv('Project Type', e(r.project_type||'-'))
            + kv('Focal Person', e(r.focal_person||'-')) + kv('Support Start', e(r.start_date))
            + kv('Support End', e(r.end_date)) + kv('Compliance', e(r.compliance_flags||'None'))
            + '</div>'
            + (r.project_goals ? '<div style="margin-top:.6rem;padding:.65rem .85rem;background:#f8f9fc;border-left:3px solid #1a3a5c;border-radius:0 4px 4px 0;font-size:.82rem;"><span style="font-size:.72rem;color:#6c757d;text-transform:uppercase;letter-spacing:.05em;">Goals</span><p style="margin:.25rem 0 0;white-space:pre-line;color:#374151;">'+e(r.project_goals)+'</p></div>' : '');

        var teamRows = team.map(function(m){ return '<tr><td style="'+S.td+'">'+e(m.name)+'</td><td style="'+S.td+'">'+e(m.role)+'</td></tr>'; }).join('');
        var custRows = customers.map(function(c){ return '<tr><td style="'+S.td+'">'+e(c.name)+'</td><td style="'+S.td+'">'+e(c.email||'-')+'</td></tr>'; }).join('');
        var teamCustHtml = sec('Project Team &amp; Customers')
            + '<div style="display:grid;grid-template-columns:1fr 1fr;gap:1rem;">'
            + '<div><div style="font-size:.75rem;font-weight:600;color:#1a3a5c;margin-bottom:.4rem;">Team Members</div>'
            + '<table style="width:100%;border-collapse:collapse;"><thead><tr><th style="'+S.th+'">Name</th><th style="'+S.th+'">Role</th></tr></thead>'
            + '<tbody>'+(teamRows||'<tr><td colspan="2" style="'+S.td+'color:#6c757d;">No team data.</td></tr>')+'</tbody></table></div>'
            + '<div><div style="font-size:.75rem;font-weight:600;color:#1a3a5c;margin-bottom:.4rem;">Customers Served</div>'
            + '<table style="width:100%;border-collapse:collapse;"><thead><tr><th style="'+S.th+'">Name</th><th style="'+S.th+'">Email</th></tr></thead>'
            + '<tbody>'+(custRows||'<tr><td colspan="2" style="'+S.td+'color:#6c757d;">No customer data.</td></tr>')+'</tbody></table></div>'
            + '</div>';

        var ticketRows = allTkts.map(function(t,i){
            return '<tr style="background:'+(i%2===0?'#fff':'#f8f9fc')+';page-break-inside:avoid;break-inside:avoid;">'
                +'<td style="'+S.tdBold+'white-space:nowrap;">'+e(t.ticket_id)+'</td>'
                +'<td style="'+S.td+'word-break:break-all;overflow-wrap:break-word;white-space:normal;hyphens:auto;">'+e(t.subject)+(t.description?'<br><span style="font-size:.72rem;color:#6c757d;">'+e(t.description)+'</span>':'')+'</td>'
                +'<td style="'+S.td+'">'+e(t.customer)+'</td>'
                +'<td style="'+S.td+'white-space:nowrap;">'+e(t.raised_on)+'</td>'
                +'<td style="'+S.td+'white-space:nowrap;">'+e(t.resolved_on)+'</td>'
                +'<td style="'+S.td+'">'+e(t.solved_by)+'</td>'
                +'<td style="'+S.td+'">'+priCell(t.priority)+'</td>'
                +'<td style="'+S.td+'">'+stateCell(t.state)+'</td>'
                +'<td style="'+S.td+'">'+slaCell(t.sla_status)+'</td>'
                +'</tr>';
        }).join('');
        var ticketHtml = sec('Ticket Register — Complete Record', true)
            + '<div style="overflow-x:auto;"><table style="width:100%;border-collapse:collapse;table-layout:fixed;">'
            + '<colgroup><col style="width:8%"><col style="width:22%"><col style="width:12%"><col style="width:9%"><col style="width:9%"><col style="width:12%"><col style="width:8%"><col style="width:10%"><col style="width:10%"></colgroup>'
            + '<thead><tr>'
            + '<th style="'+S.th+'width:8%">ID</th><th style="'+S.th+'width:22%">Subject</th>'
            + '<th style="'+S.th+'width:12%">Customer</th><th style="'+S.th+'width:9%">Raised</th>'
            + '<th style="'+S.th+'width:9%">Resolved</th><th style="'+S.th+'width:12%">Resolved By</th>'
            + '<th style="'+S.th+'width:8%">Priority</th><th style="'+S.th+'width:10%">Status</th>'
            + '<th style="'+S.th+'width:10%">SLA</th>'
            + '</tr></thead><tbody>'
            + (ticketRows||'<tr><td colspan="9" style="'+S.td+'text-align:center;color:#6c757d;padding:1rem;">No ticket data.</td></tr>')
            + '</tbody></table></div>';

        var summaryHtml = sec('Performance Summary', true)
            + '<div style="display:flex;gap:.6rem;margin-bottom:1rem;flex-wrap:wrap;page-break-inside:avoid;break-inside:avoid;">'
            + statBox(r.total_tickets,       'Total Tickets',    '#1a3a5c')
            + statBox(r.resolved_tickets,    'Resolved',         '#16a34a')
            + statBox(r.open_tickets,        'Open at Closure',  r.open_tickets>0?'#d97706':'#6c757d')
            + statBox(resolveRate+'%',       'Resolve Rate',     resolveRate>=80?'#16a34a':resolveRate>=50?'#d97706':'#dc2626')
            + statBox(r.sla_met,             'SLA Met',          '#16a34a')
            + statBox(r.sla_breached,        'SLA Breached',     r.sla_breached>0?'#dc2626':'#6c757d')
            + statBox(slaRate+'%',           'SLA Compliance',   slaRate>=80?'#16a34a':'#d97706')
            + statBox(r.avg_resolution_hrs+'h', 'Avg Resolution','#1a3a5c')
            + '</div>';

        return '<div id="portalRptContent" style="'+S.wrap+'">'
            + headerHtml + overviewHtml + teamCustHtml + ticketHtml + summaryHtml
            + '</div>';
    }

    // ── BACK BUTTON TRAP ──────────────────────────────────────────────────
    var logoutModal    = document.getElementById('logoutWarningModal');
    var modalStayBtn   = document.getElementById('modalStayBtn');
    var modalLogoutBtn = document.getElementById('modalLogoutBtn');

    var initParams = new URLSearchParams(window.location.search);
    if (!initParams.get('view')) {
        history.pushState(null, null, window.location.href);
    }
    window.addEventListener('popstate', function () {
        var params = new URLSearchParams(window.location.search);
        if (params.get('view')) return;
        history.pushState(null, null, window.location.href);
        if (logoutModal) logoutModal.classList.add('show');
    });
    window.addEventListener('pageshow', function (e) {
        if (e.persisted) {
            var showParams = new URLSearchParams(window.location.search);
            if (!showParams.get('view')) history.pushState(null, null, window.location.href);
        }
    });
    if (modalStayBtn)   modalStayBtn.addEventListener('click',   function () { if (logoutModal) logoutModal.classList.remove('show'); });
    if (modalLogoutBtn) modalLogoutBtn.addEventListener('click', function () { window.location.href = '/customer_support/logout_manual'; });
    if (logoutModal)    logoutModal.addEventListener('click',    function (e) { if (e.target === logoutModal) logoutModal.classList.remove('show'); });

    // ── AUTO SWITCH VIEW FROM URL HASH ────────────────────────────────────
    if (window.location.hash === '#reporting') {
        showReporting();
        history.replaceState(null, null, window.location.pathname);
    } else if (window.location.hash === '#kanban') {
        showKanban();
        history.replaceState(null, null, window.location.pathname);
    }
});
// bfcache guard: reload if browser restores this page from cache after logout
window.addEventListener('pageshow', function (e) {
    if (e.persisted) { window.location.reload(); }
});
